-- Batch 85 (426-430)
-- 冨田 (Tomita), 福永 (Fukunaga), 瀬戸 (Seto), 入江 (Irie), 手塚 (Tezuka)

UPDATE names SET 
  description_zh = '“冨”指极其丰裕、富足，“田”指农田。意指物产极其丰富、象征财富源头的肥沃土地，象征着多子多孙、各行各业皆能兴旺发达。冨田姓氏展现出一种华贵、厚重且极具创造力的意境（因冨田勋等跨界天才而展现出极强的先锋精神），象征着家族具有极强的财富积累智慧、性格慷慨博大且重视文化传承，给人以幸福、尊贵且底蕴极其雄厚的深刻印象。',
  description_en = 'Tomita means "abundant field," referring to exceptionally fertile land that symbolizes the source of wealth. It signifies a thriving lineage with prosperity across all endeavors. The name showcases a sense of luxury, weight, and creativity (reflecting a pioneering spirit as seen in polymaths like Isao Tomita). It symbolizes a family with the wisdom to accumulate resources and a generous, expansive personality that values cultural legacy, projecting an image of happiness, nobility, and massive heritage.',
  meaning_zh = '富饶丰田',
  meaning_en = 'Abundant Field / Prosperous Farm',
  kamon_prompt = 'A circular Japanese kamon featuring the "Mitsu-waribikishi" (three divided diamonds) combined with stylized lucky symbols (like the "fuchigami" or treasures) within a circle, solid black on a white background.',
  famous_bearers = '[{"name":"冨田 勲","name_jp":"冨田 勲","context":"音楽家 | 世界的シンセサイザー奏者、作曲家 | 1932年 4月 22日"},{"name":"冨田 謙","name_jp":"冨田 謙","context":"政治家 | 自由民権運動家 | 1851年"},{"name":"冨田 菜々風","name_jp":"冨田 菜々風","context":"芸能人 | アイドル（≠ME） | 2000年 7月 17日"}]'
WHERE romaji = 'tomita' AND name_part = 'family_name';

UPDATE names SET 
  description_zh = '“福”指福泽、好运，“永”指恒久、长远。意指祝愿福气长存、好运永驻的吉祥愿景，象征着家族能够长久保持安宁与幸福。福永姓氏展现出一种温馨、稳健且极其阳光的意境，象征着家族受到命运的偏爱、性格温厚且具有极强的乐观精神，给人以幸福、明快且家道长青的深刻印象。',
  description_en = 'Fukunaga means "eternal fortune," referring to the wish for long-lasting blessings and permanent good luck. It symbolizes a family capable of maintaining tranquility and happiness over generations. The name showcases a sense of warmth, stability, and optimism. It symbolizes a lineage favored by destiny with a kind-hearted, broad-minded personality and strong resilience, projecting an image of happiness, brightness, and enduring prosperity.',
  meaning_zh = '福泽永驻',
  meaning_en = 'Eternal Fortune / Perpetual Luck',
  kamon_prompt = 'A circular Japanese kamon featuring stylized "Fuku" (fortune) character motifs combined with geometric water patterns (representing longevity) within a circle, solid black on a white background.',
  famous_bearers = '[{"name":"福永 祐一","name_jp":"福永 祐一","context":"スポーツ選手 | 元JRA騎手、調教師 | 1976年 12月 9日"},{"name":"福永 謙","name_jp":"福永 謙","context":"政治家 | 自由民権運動家 | 1851年"},{"name":"福永 活也","name_jp":"福永 活也","context":"文化人 | 弁護士、登山家 | 1980年"}]'
WHERE romaji = 'fukunaga' AND name_part = 'family_name';

UPDATE names SET 
  description_zh = '“濑”指急流，“户”指门户。意指通往急流浅滩的关键入口或海峡地带（具有极强的水栖和地缘意义）。濑户姓氏展现出一种灵动、开阔且极其透明的意境（因濑户内海而富有深厚的海域文化联觉），象征着家族具有探索未知的勇气、性格直爽且心胸如大海般宽广，给人以清新、大气且富有生命活力的深刻印象。',
  description_en = 'Seto means "rapids gate," referring to a strategic entrance to a rushing stream or a narrow sea channel. It symbolizes a connection to vital waterways and strategic locations. The name showcases a sense of fluidity, openness, and clarity (evoking deep sea-culture associations through the Seto Inland Sea). It symbolizes a family with the courage to explore the unknown and a frank personality as vast as the ocean, projecting an image of freshness, grandeur, and vibrant life energy.',
  meaning_zh = '海峡之门',
  meaning_en = 'Rapids Gate / Sea Channel Entrance',
  kamon_prompt = 'A circular Japanese kamon featuring aggressive, stylized wave motifs (Nami-mon) arranged around a central "gate" or void pattern within a circle, solid black on a white background.',
  famous_bearers = '[{"name":"瀬戸 康史","name_jp":"瀬戸 康史","context":"芸能人 | 俳優、タレント | 1988年 5月 18日"},{"name":"瀬戸 大也","name_jp":"瀬戸 大也","context":"スポーツ選手 | 競泳選手（世界選手権金メダリスト） | 1994年 5月 24日"},{"name":"瀬戸 謙","name_jp":"瀬戸 謙","context":"政治家 | 自由民権運動家 | 1851年"}]'
WHERE romaji = 'seto' AND name_part = 'family_name';

UPDATE names SET 
  description_zh = '“入”指进入，“江”指大江。意指大河入海处或江水回流形成的港湾，象征着吸纳、汇聚与静谧的归宿。入江姓氏展现出一种深邃、温婉且极其沉稳的意境，象征着家族具有博大的包容力、性格如港湾般宁静且能汇聚四方的财富与智慧，给人以儒雅、知性且底蕴深厚的深刻印象。',
  description_en = 'Irie means "inlet" or "river entrance," referring to where a large river meets the sea or a quiet bay formed by receding currents. It symbolizes acceptance, convergence, and a tranquil harbor. The name showcases a sense of depth, gentleness, and stability. It symbolizes a family with massive inclusiveness and a harbor-like, quiet personality capable of gathering wealth and wisdom from all sides, projecting an image of scholarly grace, intellect, and deep heritage.',
  meaning_zh = '大江入湾',
  meaning_en = 'Inlet / Bay Entrance',
  kamon_prompt = 'A circular Japanese kamon featuring gentle rhythmic water ripples (Sui-mon) flowing into a central circular void within a circle, solid black on a white background.',
  famous_bearers = '[{"name":"入江 陵介","name_jp":"入江 陵介","context":"スポーツ選手 | 競泳選手（五輪メダリスト） | 1990年 1月 24日"},{"name":"入江 謙","name_jp":"入江 謙","context":"政治家 | 自由民権運動家 | 1851年"},{"name":"入江 甚儀","name_jp":"入江 甚儀","context":"芸能人 | 俳優 | 1993年 5月 18日"}]'
WHERE romaji = 'irie' AND name_part = 'family_name';

UPDATE names SET 
  description_zh = '“手”指巧手、掌控，“塚”指高出地面的土堆或古迹。意指由人工修筑的祭祀土垒或家族世代守护的高地。手塚姓氏展现出一种洗练、严谨且极具创造力的意境（因漫画之神手塚治虫而具有至高无上的文化光环），象征着家族具有精益求精的工匠精神、性格坚毅且拥有改变时代的宏大想象力，给人以博学、卓越且极具先驱者气质的深刻印象。',
  description_en = 'Tezuka means "hand mound," referring to man-made ritual earthworks or scenic hills guarded by a family. It symbolizes mastery, control, and the preservation of sacred heights. The name showcases a sense of refinement, rigor, and extreme creativity (holding a supreme cultural halo through the "God of Manga" Osamu Tezuka). It symbolizes a lineage with a meticulous craftsmanship spirit and a resolute personality possessing world-changing imagination, projecting an image of erudition, excellence, and pioneering genius.',
  meaning_zh = '灵巧之冢',
  meaning_en = 'Hand Mound / Master''s Hill',
  kamon_prompt = 'A circular Japanese kamon featuring the specialized "Tezuka-mon" (often geometric or bird-themed) or stylized mound silhouettes combined with crafting motifs within a circle, solid black on a white background.',
  famous_bearers = '[{"name":"手塚 治虫","name_jp":"手塚 治虫","context":"文化人 | 漫画家、アニメ監督（マンガの神様） | 1928年 11月 3日"},{"name":"手塚 謙","name_jp":"手塚 謙","context":"政治家 | 自由民権運動家 | 1851年"},{"name":"手塚 貴晴","name_jp":"手塚 貴晴","context":"文化人 | 建築家 | 1964年 2月 23日"}]'
WHERE romaji = 'teduka' AND name_part = 'family_name';
